import{_ as o,o as t,c,a2 as d}from"./chunks/framework.BKG_UbFK.js";const m=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/architecture.md","filePath":"fr/guide/architecture.md"}'),r={name:"fr/guide/architecture.md"};function a(s,e,i,n,l,u){return t(),c("div",null,[...e[0]||(e[0]=[d('<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="comment-fonctionne-la-resolution" tabindex="-1">Comment fonctionne la résolution <a class="header-anchor" href="#comment-fonctionne-la-resolution" aria-label="Permalink to &quot;Comment fonctionne la résolution&quot;">​</a></h2><p><code>resolveFor()</code> est le cœur de l&#39;autorisation contextuelle de Clearance - voir <a href="/clearance-docs/fr/features/contextual-authorization.html">Autorisation contextuelle</a> pour l&#39;API complète. Elle fusionne trois sources, dans cet ordre de priorité :</p><ol><li><strong>Attributions de rôle contextuelles</strong> - permissions issues des rôles que l&#39;utilisateur détient spécifiquement dans ce contexte (<code>clr_role_ctx</code>).</li><li><strong>Attributions de rôle globales</strong> - permissions issues des rôles Spatie assignés globalement à l&#39;utilisateur (ainsi <code>super_admin</code> et les autres rôles globaux satisfont <code>canIn()</code> pour n&#39;importe quel contexte).</li><li><strong>Surcharges par contexte</strong> (<code>clr_ctx_overrides</code>) - <code>forced_on</code> ajoute une permission en plus de ce qui précède ; <code>forced_off</code> la retire, même si la permission a été accordée par un rôle global. Un refus l&#39;emporte toujours.</li></ol><div class="warning custom-block"><p class="custom-block-title">Un refus l&#39;emporte toujours</p><p><code>forced_off</code> prime sur toute permission accordée par un rôle global ou une attribution de rôle contextuelle. Il n&#39;existe aucun moyen de &quot;surclasser&quot; une surcharge <code>forced_off</code> pour le même utilisateur/permission/contexte, sinon en la supprimant.</p></div><h2 id="base-de-donnees" tabindex="-1">Base de données <a class="header-anchor" href="#base-de-donnees" aria-label="Permalink to &quot;Base de données&quot;">​</a></h2><p>Clearance possède 6 tables et ne modifie jamais les tables principales de Spatie (<code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, <code>role_has_permissions</code>). Toutes les clés étrangères référençant <code>roles.id</code>/<code>permissions.id</code> sont en cascade à la suppression sauf mention contraire ; les tables Spatie n&#39;ont aucune clé étrangère pointant vers <code>clr_*</code>.</p><table tabindex="0"><thead><tr><th>Table</th><th>Colonnes clés</th></tr></thead><tbody><tr><td><code>clr_meta</code></td><td><code>subject_type</code>, <code>subject_key</code> (uniques ensemble) - <code>display_name</code>, <code>description</code>, <code>icon_svg</code>, <code>color</code> - métadonnées d&#39;affichage pour un rôle ou une garde</td></tr><tr><td><code>clr_role_meta</code></td><td><code>role_id</code> (unique, FK -&gt; <code>roles</code>) - <code>is_locked</code>, <code>scope</code> (<code>global</code>|<code>contextual</code>), <code>context_types</code> (json) - <code>parent_role_id</code> (FK nullable -&gt; <code>roles</code>, <code>ON DELETE SET NULL</code>) - rôle plafond</td></tr><tr><td><code>clr_guards</code></td><td><code>name</code> (unique), <code>driver</code>, <code>provider</code> - gardes gérés via le panneau</td></tr><tr><td><code>clr_settings</code></td><td><code>key</code> (unique), <code>value</code> - magasin clé/valeur à l&#39;exécution (rôle par défaut, etc.)</td></tr><tr><td><code>clr_role_ctx</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>context_type</code>, <code>context_id</code> - attributions de rôle contextuelles, unique par <code>(user, role, context_type, context_id)</code></td></tr><tr><td><code>clr_ctx_overrides</code></td><td><code>user_id</code>, <code>role_id</code> (FK -&gt; <code>roles</code>), <code>permission_id</code> (FK -&gt; <code>permissions</code>), <code>context_type</code>, <code>context_id</code>, <code>type</code> (<code>forced_on</code>|<code>forced_off</code>) - surcharges de permission par utilisateur, par contexte</td></tr></tbody></table><h2 id="ne-touche-jamais-aux-tables-de-spatie" tabindex="-1">Ne touche jamais aux tables de Spatie <a class="header-anchor" href="#ne-touche-jamais-aux-tables-de-spatie" aria-label="Permalink to &quot;Ne touche jamais aux tables de Spatie&quot;">​</a></h2><p>Clearance est conçu pour coexister avec <code>spatie/laravel-permission</code>, pas pour le remplacer. Chaque enregistrement <code>Role</code> et <code>Permission</code> qu&#39;un panneau Clearance crée ou modifie est un véritable modèle Spatie, stocké dans les propres tables de Spatie. Clearance n&#39;exécute jamais de migration ajoutant une colonne à, ou écrivant une clé étrangère depuis, l&#39;une des tables <code>roles</code>, <code>permissions</code>, <code>model_has_roles</code>, <code>model_has_permissions</code>, ou <code>role_has_permissions</code>.</p><p>Toutes les données propres à Clearance - métadonnées d&#39;affichage, portée et plafonds de rôle, assignations contextuelles, surcharges par contexte, définitions de garde et paramètres - vivent exclusivement dans les 6 tables <code>clr_*</code> ci-dessus. Cela signifie que :</p><ul><li>Désinstaller Clearance ne risque jamais de corrompre vos données de rôle/permission Spatie existantes.</li><li>Tout code lisant déjà directement les modèles ou tables de Spatie continue de fonctionner sans modification.</li><li>Les fonctionnalités contextuelles et de plafond de Clearance sont des couches purement additives résolues au moment de la requête (via <code>resolveFor()</code> et <code>RoleService</code>), et non intégrées au schéma de Spatie.</li></ul><h2 id="voir-aussi" tabindex="-1">Voir aussi <a class="header-anchor" href="#voir-aussi" aria-label="Permalink to &quot;Voir aussi&quot;">​</a></h2><ul><li><a href="/clearance-docs/fr/features/contextual-authorization.html">Autorisation contextuelle</a> - <code>canIn()</code>, <code>hasRoleIn()</code>, directives Blade, <code>ContextService</code></li><li><a href="/clearance-docs/fr/features/roles.html">Rôles</a> - portée et rôles plafonds, <code>RoleService::setParent()</code></li><li><a href="/clearance-docs/fr/guide/migration.html">Migration</a> - amorcer <code>clr_meta</code>/<code>clr_role_meta</code>/<code>clr_guards</code> sur une installation Spatie existante</li><li><a href="/clearance-docs/fr/guide/security.html">Sécurité</a> - comment le modèle de plafond et de surcharge prévient l&#39;élévation de privilèges</li></ul>',14)])])}const _=o(r,[["render",a]]);export{m as __pageData,_ as default};
